// Prompt builders
const buildAskPrompt = (topic, historyText) =>
  `${historyText ? `${historyText}\n` : ''}${socraticGuidelines} about "${topic}".`;

const buildAnswerPrompt = (question, historyText) => `${
  historyText ? `${historyText}\n` : ''
