        ambiguousItems.push({
          type: 'ambiguous',
          itemIndex: index,
          tags,
          tagCount: 1,
        });
      }
    }
  });

  problematicItems.push(...untaggedItems, ...overtaggedItems, ...ambiguousItems);

  return {
    stats,
    mostUsed,
    leastUsed,
    problematicItems,
    sortedTags, // Include full sorted list for additional analysis if needed
  };
}

